#include <stdio.h>
#include <string.h>

int win(char chef, char opp) {
    if (chef == 'R' && opp == 'S') return 1;
    if (chef == 'P' && opp == 'R') return 1;
    if (chef == 'S' && opp == 'P') return 1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char A[100005]; scanf("%s", A);
        int prev[3] = {0,0,0}, cur[3];
        // 0:R,1:P,2:S
        for (int i = 0; i < N; ++i) {
            for (int c = 0; c < 3; ++c) cur[c] = -1000000;
            for (int p = 0; p < 3; ++p) {
                for (int c = 0; c < 3; ++c) if (c != p) {
                    int add = win(c==0?'R':c==1?'P':'S', A[i]);
                    if (prev[p] + add > cur[c]) cur[c] = prev[p] + add;
                }
            }
            for (int c = 0; c < 3; ++c) prev[c] = cur[c];
        }
        int ans = prev[0];
        if (prev[1] > ans) ans = prev[1];
        if (prev[2] > ans) ans = prev[2];
        printf("%d\n", ans);
    }
    return 0;
}

