code.Java:
import java.io.*;
import java.util.*;
public class Main {
    static boolean win(char chef, char opp){
        return (chef=='R' && opp=='S') || (chef=='P' && opp=='R') || (chef=='S' && opp=='P');
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            char[] A = br.readLine().trim().toCharArray();
            int[] prev = new int[3]; // all zero
            int[] cur = new int[3];
            for(char opp: A){
                Arrays.fill(cur, Integer.MIN_VALUE/2);
                for(int p=0;p<3;++p){
                    for(int c=0;c<3;++c) if(c!=p){
                        int add = win(c==0?'R':c==1?'P':'S', opp) ? 1 : 0;
                        cur[c] = Math.max(cur[c], prev[p] + add);
                    }
                }
                System.arraycopy(cur,0,prev,0,3);
            }
            int ans = Math.max(prev[0], Math.max(prev[1], prev[2]));
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def win(chef, opp):
    return (chef=='R' and opp=='S') or (chef=='P' and opp=='R') or (chef=='S' and opp=='P')

def solve():
    data = sys.stdin.read().strip().split()
    if not data: return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        A = next(it).strip()
        prev = [0,0,0]  # R,P,S
        for opp in A:
            cur = [-10**9]*3
            for p in range(3):
                for c in range(3):
                    if c==p: continue
                    add = 1 if win('R' if c==0 else 'P' if c==1 else 'S', opp) else 0
                    cur[c] = max(cur[c], prev[p] + add)
            prev = cur
        out.append(str(max(prev)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

